import { useReducer } from 'react';

const initialState = { count: 0 };

function reducer(state, action) {
  switch (action.type) {
    case 'increment':
      return { count: state.count + 1 };
    case 'decrement':
      return { count: state.count - 1 };
    case 'reset':
      return initialState;
    default:
      throw new Error(`Unknown action: ${action.type}`);
  }
}

export default function Counter() {
  const [state, dispatch] = useReducer(reducer, initialState);

  return (
    <div>
      <p>Count: {state.count}</p>
      <button onClick={() => dispatch({ type: 'increment' })}>+</button>
      <button onClick={() => dispatch({ type: 'decrement' })}>-</button>
      <button onClick={() => dispatch({ type: 'reset' })}>Reset</button>
    </div>
  );
}

import { useReducer } from 'react';

const initialForm = { name: '', email: '', submitted: false };

function formReducer(state, action) {
  switch (action.type) {
    case 'field':
      return { ...state, [action.field]: action.value };
    case 'submit':
      return { ...state, submitted: true };
    case 'reset':
      return initialForm;
    default:
      return state;
  }
}

export default function SignupForm() {
  const [form, dispatch] = useReducer(formReducer, initialForm);

  const handleChange = e =>
    dispatch({ type: 'field', field: e.target.name, value: e.target.value });

  return (
    <form onSubmit={e => { e.preventDefault(); dispatch({ type: 'submit' }); }}>
      <input name="name" value={form.name} onChange={handleChange} placeholder="Name" />
      <input name="email" value={form.email} onChange={handleChange} placeholder="Email" />
      <button type="submit">Submit</button>
      {form.submitted && <p>Thank you, {form.name}!</p>}
    </form>
  );
}

import { useState, useMemo } from 'react';

function slowFilter(items, query) {
  // Simulates an expensive operation
  return items.filter(item => item.toLowerCase().includes(query.toLowerCase()));
}

export default function SearchList({ items }) {
  const [query, setQuery] = useState('');
  const [darkMode, setDarkMode] = useState(false);

  // Only recalculates when items or query changes, not when darkMode toggles
  const filtered = useMemo(() => slowFilter(items, query), [items, query]);

  return (
    <div>
      <input value={query} onChange={e => setQuery(e.target.value)} placeholder="Search..." />
      <button onClick={() => setDarkMode(d => !d)}>Toggle theme</button>
      <ul>{filtered.map(item => <li key={item}>{item}</li>)}</ul>
    </div>
  );
}

