import { useReducer, useRef, FormEvent, ChangeEvent } from 'react';

type Action = { type: 'set'; value: string } | { type: 'clear' };

function reducer(state: string, action: Action): string {
  switch (action.type) {
    case 'set': return action.value;
    case 'clear': return '';
    default: return state;
  }
}

export default function SearchBox() {
  const [query, dispatch] = useReducer(reducer, '');
  const inputRef = useRef<HTMLInputElement>(null);

  const handleChange = (e: ChangeEvent<HTMLInputElement>) =>
    dispatch({ type: 'set', value: e.target.value });

  const handleSubmit = (e: FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    console.log('Searching for:', query);
    dispatch({ type: 'clear' });
    inputRef.current?.focus();
  };

  return (
    <form onSubmit={handleSubmit}>
      <input ref={inputRef} value={query} onChange={handleChange} />
      <button type="submit">Search</button>
    </form>
  );
}

