import { createContext, useContext, useState } from 'react';

const TabsContext = createContext<{ active: string; setActive: (t: string) => void } | null>(null);
const useTabs = () => { const ctx = useContext(TabsContext); if (!ctx) throw new Error(); return ctx; };

function Tabs({ children, defaultTab }: { children: React.ReactNode; defaultTab: string }) {
  const [active, setActive] = useState(defaultTab);
  return <TabsContext.Provider value={{ active, setActive }}>{children}</TabsContext.Provider>;
}

function Tab({ name, children }: { name: string; children: React.ReactNode }) {
  const { active, setActive } = useTabs();
  return (
    <button
      style={{ fontWeight: active === name ? 'bold' : 'normal' }}
      onClick={() => setActive(name)}
    >{children}</button>
  );
}

function TabPanel({ name, children }: { name: string; children: React.ReactNode }) {
  const { active } = useTabs();
  return active === name ? <div>{children}</div> : null;
}

// Attach sub-components
Tabs.Tab = Tab;
Tabs.Panel = TabPanel;

